INSERT INTO `ai_community_event` VALUES (7, 'AIеҲҶй’ҹзә§еӨ©ж°”йў„жҠҘдёҠзәҝпјҢзІҫеҮҶжңҚеҠЎеёӮж°‘еҮәиЎҢ', 'ж·ұеңіеёӮж°”иұЎеұҖиҒ”еҗҲи…ҫи®Ҝдә‘жҺЁеҮәAIеҲҶй’ҹзә§еӨ©ж°”йў„жҠҘзі»з»ҹпјҢеҸҜе®һзҺ°жңӘжқҘ2е°Ҹж—¶еҶ…йҖҗ10еҲҶй’ҹйҷҚйӣЁйў„жҠҘпјҢеҮҶзЎ®зҺҮи¶…иҝҮ90%гҖӮзі»з»ҹе·ІжҺҘе…ҘеҹҺеёӮдәӨйҖҡгҖҒж°ҙеҠЎзӯүйғЁй—ЁпјҢдёәеёӮж°‘еҮәиЎҢжҸҗдҫӣзІҫеҮҶж°”иұЎжңҚеҠЎгҖӮ', 'еә”з”ЁиҗҪең°', 'дёӯ', 'е»әи®®е…¶д»–еҹҺеёӮеҖҹйүҙж·ұеңіз»ҸйӘҢпјҢжҺЁеҠЁAIеӨ©ж°”йў„жҠҘдёҺеҹҺеёӮжІ»зҗҶж·ұеәҰиһҚеҗҲгҖӮйҮҚзӮ№еҠ ејәжҡҙйӣЁгҖҒеҶ…ж¶қзӯүзҒҫе®іжҖ§еӨ©ж°”зҡ„зІҫз»ҶеҢ–йў„жҠҘиғҪеҠӣпјҢжҸҗеҚҮеёӮж°‘иҺ·еҫ—ж„ҹгҖӮ', '0', '2026-03-30 20:00:49');
INSERT INTO `ai_community_event` VALUES (8, 'AIеӨ©ж°”йў„жҠҘеҮҶзЎ®зҺҮдәүи®®пјҡз”ЁжҲ·иҙЁз–‘й«ҳжё©йў„жҠҘеҒҸдҪҺ', 'иҝ‘жңҹжҢҒз»ӯй«ҳжё©еӨ©ж°”пјҢеӨҡең°з”ЁжҲ·еҸҚйҰҲдё»жөҒеӨ©ж°”Appзҡ„AIйў„жҠҘжё©еәҰдёҺе®һйҷ…дҪ“ж„ҹе·®ејӮиҫғеӨ§пјҢйғЁеҲҶеҹҺеёӮйў„жҠҘжё©еәҰеҒҸдҪҺ3-5в„ғгҖӮж°”иұЎдё“е®¶и§ЈйҮҠз§°пјҢдҪ“ж„ҹжё©еәҰеҸ—ж№ҝеәҰгҖҒйЈҺйҖҹзӯүеӨҡеӣ зҙ еҪұе“ҚпјҢAIжЁЎеһӢйңҖиҝӣдёҖжӯҘдјҳеҢ–гҖӮ', 'з”ЁжҲ·еҸҚйҰҲ', 'дёӯ', 'е»әи®®еӨ©ж°”жңҚеҠЎдјҒдёҡдјҳеҢ–AIйў„жҠҘжЁЎеһӢпјҢеј•е…ҘдҪ“ж„ҹжё©еәҰгҖҒзғӯжҢҮж•°зӯүжҢҮж ҮгҖӮеҗҢж—¶еҠ ејәз”ЁжҲ·жІҹйҖҡпјҢжё…жҷ°еұ•зӨәйў„жҠҘзҡ„дёҚзЎ®е®ҡжҖ§иҢғеӣҙпјҢжҸҗеҚҮз”ЁжҲ·дҪ“йӘҢе’ҢдҝЎд»»еәҰгҖӮ', '0', '2026-03-30 20:00:49');
INSERT INTO `ai_community_event` VALUES (9, 'ж°”иұЎеұҖеҸ‘еёғAIеӨ©ж°”йў„жҠҘжҠҖжңҜзҷҪзҡ®д№Ұ', 'дёӯеӣҪж°”иұЎеұҖжӯЈејҸеҸ‘еёғгҖҠдәәе·ҘжҷәиғҪеӨ©ж°”йў„жҠҘжҠҖжңҜзҷҪзҡ®д№ҰгҖӢпјҢжҸҗеҮәжһ„е»ә\"ж•°еҖјйў„жҠҘ+AI\"иһҚеҗҲзҡ„жҠҖжңҜи·ҜзәҝпјҢжҳҺзЎ®жңӘжқҘ5е№ҙAIеӨ©ж°”йў„жҠҘзҡ„еҸ‘еұ•зӣ®ж Үе’ҢйҮҚзӮ№д»»еҠЎгҖӮиҝҷжҳҜжҲ‘еӣҪйҰ–дёӘAIж°”иұЎйўҶеҹҹзҡ„е®ҳж–№жҠҖжңҜжҢҮеҚ—гҖӮ', 'ж”ҝзӯ–жі•и§„', 'й«ҳ', 'е»әи®®ж°”иұЎзӣёе…ідјҒдёҡе’Ңз ”з©¶жңәжһ„и®ӨзңҹеӯҰд№ зҷҪзҡ®д№ҰеҶ…е®№пјҢжҠҠжҸЎжҠҖжңҜеҸ‘еұ•ж–№еҗ‘гҖӮз§ҜжһҒеҸӮдёҺAIж°”иұЎжҠҖжңҜж ҮеҮҶеҲ¶е®ҡпјҢдәүеҸ–еңЁеӣҪе®¶зә§йЎ№зӣ®дёӯеҸ‘жҢҘжӣҙеӨ§дҪңз”ЁгҖӮ', '0', '2026-03-30 20:00:49');
INSERT INTO `ai_community_event` VALUES (10, 'йҰ–дёӘAIж°”иұЎдё»ж’ӯдә®зӣёеӨ®и§ҶеӨ©ж°”йў„жҠҘ', 'еӨ®и§ҶгҖҠеӨ©ж°”йў„жҠҘгҖӢж Ҹзӣ®еј•е…ҘAIиҷҡжӢҹдё»ж’ӯ\"йЈҺжҷ“\"пјҢеҸҜе®һж—¶з”ҹжҲҗж°”иұЎи§ЈиҜҙи§Ҷйў‘пјҢж”ҜжҢҒеӨҡиҜӯиЁҖж’ӯжҠҘгҖӮAIдё»ж’ӯдёҠеІ—йҰ–е‘Ёж”¶и§ҶзҺҮжҸҗеҚҮ12%пјҢдҪҶйғЁеҲҶи§Ӯдј—и®Өдёәзјәе°‘дәәжғ…е‘іпјҢжңҹеҫ…жҠҖжңҜжҢҒз»ӯж”№иҝӣгҖӮ', 'жҠҖжңҜеҲӣж–°', 'дҪҺ', 'е»әи®®еӘ’дҪ“жңәжһ„жҺўзҙўAIдё»ж’ӯдёҺдј з»ҹдё»жҢҒдәәз»“еҗҲзҡ„ж’ӯжҠҘжЁЎејҸпјҢеңЁдҝқжҢҒдё“дёҡжҖ§зҡ„еҗҢж—¶еўһејәдә’еҠЁжҖ§гҖӮеҸҜй’ҲеҜ№дёҚеҗҢиҠӮзӣ®еңәжҷҜзҒөжҙ»йҖүжӢ©AIжҲ–зңҹдәәж’ӯжҠҘж–№ејҸгҖӮ', '0', '2026-03-30 20:00:49');
INSERT INTO `ai_community_event` VALUES (11, 'AIеӨ©ж°”йў„жҠҘжңҚеҠЎе•Ҷеӣ ж•°жҚ®йҖ еҒҮиў«зәҰи°Ҳ', 'жҹҗе•ҶдёҡеӨ©ж°”Appиў«жӣқдҪҝз”ЁAIз”ҹжҲҗиҷҡеҒҮж°”иұЎж•°жҚ®пјҢеӨёеӨ§йў„жҠҘиғҪеҠӣеҗёеј•д»ҳиҙ№з”ЁжҲ·гҖӮеӣҪе®¶зҪ‘дҝЎеҠһиҒ”еҗҲж°”иұЎйғЁй—Ёе·ІзәҰи°Ҳзӣёе…іиҙҹиҙЈдәәпјҢиҙЈд»ӨдёӢжһ¶иҝқи§„еҠҹиғҪе№¶ж•ҙж”№гҖӮиҜҘдәӢд»¶еј•еҸ‘иЎҢдёҡеҜ№AIеӨ©ж°”йў„жҠҘзңҹе®һжҖ§зҡ„е№ҝжіӣи®Ёи®әгҖӮ', 'еҗҲи§„дәӢд»¶', 'дёҘйҮҚ', 'е»әи®®еӨ©ж°”жңҚеҠЎдјҒдёҡдёҘж јйҒөе®ҲгҖҠж°”иұЎжі•гҖӢе’ҢгҖҠж•°жҚ®е®үе…Ёжі•гҖӢпјҢзЎ®дҝқйў„жҠҘж•°жҚ®зңҹе®һеҮҶзЎ®гҖӮе»әз«ӢеҶ…йғЁж•°жҚ®е®Ўж ёжңәеҲ¶пјҢжқңз»қAIз”ҹжҲҗиҷҡеҒҮдҝЎжҒҜзҡ„иҝқи§„иЎҢдёәгҖӮ', '0', '2026-03-30 20:00:49');
