INSERT INTO `ai_community_event` VALUES (70, 'е…ідәҺвҖңжң¬ең°вҖқжҰӮеҝөзҡ„еӨҡеңәжҷҜи®Ёи®әдёҺжҠҖжңҜдҝЎжҒҜжұҮжҖ»', 'еҶ…е®№еҢ…еҗ«еӨҡдёӘж—¶й—ҙзӮ№зҡ„и®Ёи®әзүҮж®өпјҢж¶үеҸҠпјҡ1. 2025е№ҙ6жңҲ25ж—Ҙе…ідәҺжң¬ең°йғЁзҪІеӨ§жЁЎеһӢпјҲеҰӮ700дәҝеҸӮж•°д»ҘдёҠи§„жЁЎпјүдёҺе®ҳзҪ‘зүҲжң¬жҖ§иғҪе·®ејӮзҡ„и®Ёи®әпјҢжҢҮеҮәйҮҸеҢ–зүҲжң¬дёҺж»ЎиЎҖзүҲзҡ„е·®и·қпјӣ2. 2021е№ҙ9жңҲ6ж—ҘеҜ№вҖңжң¬ең°вҖқдёҺвҖңеҪ“ең°вҖқиҜҚиҜӯеҢәеҲ«зҡ„йҮҠд№үпјӣ3. 2024е№ҙ1жңҲ31ж—ҘгҖҒ2025е№ҙ10жңҲ7ж—ҘгҖҒ2021е№ҙ11жңҲ26ж—ҘгҖҒ2021е№ҙ2жңҲ1ж—ҘзӯүеӨҡдёӘж—¶й—ҙзӮ№е…ідәҺWindowsзі»з»ҹж“ҚдҪңжҢҮеҚ—пјҲеҰӮжү“ејҖжҺ§еҲ¶йқўжқҝгҖҒжң¬ең°з»„зӯ–з•Ҙзј–иҫ‘еҷЁгҖҒжң¬ең°з”ЁжҲ·е’Ңз»„зӯүпјүзҡ„иҜҙжҳҺпјӣ4. 2020е№ҙ6жңҲ24ж—ҘдёҺ2018е№ҙ3жңҲ13ж—Ҙе…ідәҺжүӢжңәжң¬ең°йҳ…иҜ»AppпјҲеҰӮiOSеұұдёҳйҳ…иҜ»еҷЁгҖҒPerfect ViewerзңӢжј«з”»е·Ҙе…·пјүзҡ„жҺЁиҚҗпјӣ5. 2025е№ҙ7жңҲ18ж—ҘWin11д»Һеҫ®иҪҜиҙҰжҲ·еҲҮжҚўеҲ°жң¬ең°иҙҰжҲ·зҡ„ж–№жі•гҖӮеҶ…е®№дёәжҠҖжңҜи®Ёи®әдёҺж“ҚдҪңжҢҮеҚ—зҡ„ж··еҗҲпјҢж— жҳҺжҳҫзҙ§жҖҘдәӢд»¶жҲ–е®үе…ЁйЈҺйҷ©гҖӮ', 'notice', 'normal', 'иҜҘеҶ…е®№дёәдёҚеҗҢж—¶й—ҙжҠҖжңҜи®Ёи®әдёҺж“ҚдҪңжҢҮеҚ—зҡ„ж··еҗҲпјҢдҝЎжҒҜиҫғдёәйӣ¶ж•Јдё”ж— жҳҺзЎ®ж—¶ж•ҲжҖ§жҲ–зҙ§жҖҘйЈҺйҷ©гҖӮе»әи®®пјҡ1. иӢҘйңҖжҸҗеҸ–жҠҖжңҜдҝЎжҒҜпјҢеҸҜжҢүдё»йўҳпјҲеҰӮеӨ§жЁЎеһӢйғЁзҪІгҖҒзі»з»ҹж“ҚдҪңгҖҒиҪҜд»¶жҺЁиҚҗпјүеҲҶзұ»ж•ҙзҗҶпјӣ2. жіЁж„ҸеҶ…е®№дёӯж—¶й—ҙи·ЁеәҰиҫғеӨ§пјҢйғЁеҲҶж“ҚдҪңжҢҮеҚ—еҸҜиғҪйҡҸзі»з»ҹжӣҙж–°иҖҢиҝҮж—¶пјҢйңҖж ёе®һеҪ“еүҚйҖӮз”ЁжҖ§пјӣ3. ж— йңҖиҰҒз«ӢеҚіеӨ„зҗҶзҡ„зӨҫеҢәе®үе…ЁжҲ–зҙ§жҖҘдәӢеҠЎпјҢеҸҜеҪ’жЎЈдёәжҷ®йҖҡдҝЎжҒҜеҸӮиҖғгҖӮ', '0', NULL);
INSERT INTO `ai_community_event` VALUES (71, 'е…ідәҺвҖңжң¬ең°вҖқжҰӮеҝөзҡ„еӨҡйҮҚеҗ«д№үдёҺдҪҝз”ЁеңәжҷҜи®Ёи®ә', 'еҶ…е®№и®Ёи®әдәҶвҖңжң¬ең°вҖқдёҖиҜҚеңЁдёҚеҗҢиҜӯеўғдёӢзҡ„еӨҡз§Қеҗ«д№үпјҡ1. жҢҮдјҒдёҡз§ҒжңүеҢ–йғЁзҪІзҡ„еӨ§и§„жЁЎAIжЁЎеһӢпјҲеҰӮ700дәҝеҸӮж•°д»ҘдёҠпјүпјҢдёҺдёӘдәәз”өи„‘дёҠзҡ„е°ҸжЁЎеһӢеҜ№жҜ”пјӣ2. жҢҮжң¬ең°йғЁзҪІзҡ„йҮҸеҢ–зүҲдёҺе®ҳзҪ‘ж»ЎиЎҖзүҲAIжЁЎеһӢзҡ„жҖ§иғҪе·®и·қпјӣ3. и®Ўз®—жңәж“ҚдҪңдёӯзҡ„вҖңжң¬ең°з”ЁжҲ·е’Ңз»„вҖқгҖҒвҖңжҺ§еҲ¶йқўжқҝвҖқзӯүзі»з»ҹз®ЎзҗҶжҰӮеҝөпјӣ4. ең°зҗҶж„Ҹд№үдёҠзҡ„вҖңжң¬ең°вҖқдёҺвҖңеҪ“ең°вҖқзҡ„еҢәеҲ«пјӣ5. жүӢжңәжң¬ең°йҳ…иҜ»APPжҺЁиҚҗпјӣ6. Windowsзі»з»ҹеҫ®иҪҜиҙҰжҲ·дёҺжң¬ең°иҙҰжҲ·зҡ„еҲҮжҚўж–№жі•пјӣ7. жЁЎжӢҹеҷЁе®үиЈ…жң¬ең°APKж–Үд»¶зҡ„ж–№жі•пјӣ8. еҝҳи®°жң¬ең°иҙҰжҲ·еҜҶз Ғзҡ„и§ЈеҶіж–№жЎҲпјӣ9. жң¬ең°зңӢжј«з”»иҪҜд»¶жҺЁиҚҗгҖӮеҶ…е®№з”ұеӨҡдёӘдёҚеҗҢж—¶й—ҙгҖҒдёҚеҗҢдё»йўҳзҡ„зүҮж®өжӢјжҺҘиҖҢжҲҗпјҢж¶үеҸҠжҠҖжңҜгҖҒең°зҗҶгҖҒи®Ўз®—жңәж“ҚдҪңзӯүеӨҡдёӘйўҶеҹҹгҖӮ', 'notice', 'normal', 'иҜҘеҶ…е®№дёәдҝЎжҒҜжұҮзј–пјҢйқһеҚ•дёҖдәӢд»¶гҖӮе»әи®®пјҡ1. иӢҘз”ЁдәҺзҹҘиҜҶж•ҙзҗҶпјҢеҸҜжҢүдё»йўҳпјҲеҰӮAIйғЁзҪІгҖҒи®Ўз®—жңәж“ҚдҪңгҖҒиҪҜд»¶еә”з”ЁпјүеҜ№дҝЎжҒҜиҝӣиЎҢеҲҶзұ»йҮҚз»„гҖӮ2. иӢҘз”ЁдәҺзӨҫеҢәйҖҡзҹҘпјҢйңҖжҸҗеҸ–ж ёеҝғдё»йўҳе№¶йҮҚж–°з»„з»ҮжҲҗиҝһиҙҜзҡ„иҜҙжҳҺж–Үжң¬пјҢйҒҝе…ҚзүҮж®өе Ҷз ҢгҖӮ3. жіЁж„ҸиҫЁеҲ«дёҚеҗҢзүҮж®өзҡ„ж—¶й—ҙжңүж•ҲжҖ§пјҲеҰӮ2024гҖҒ2025е№ҙзҡ„ж“ҚдҪңжҢҮеҚ—еҸҜиғҪе…·жңүж—¶ж•ҲжҖ§пјүгҖӮ', '0', NULL);
