INSERT INTO `ai_community_event` VALUES (120, 'жң¬ең°зӣҙж’ӯдё“дёҡзүҲжңҚеҠЎејӮеёё', 'жң¬ең°зӣҙж’ӯдё“дёҡзүҲжңҚеҠЎдәҺжҠ–йҹіз”ҹжҙ»жңҚеҠЎе•Ҷе®¶дёҺиҫҫдәәпјҢжҸҗдҫӣдёҖз«ҷејҸзӣҙж’ӯи§ЈеҶіж–№жЎҲпјҢзҺ©иҪ¬жң¬ең°зӣҙж’ӯеёҰиҙ§гҖӮеҪ“еүҚеҮәзҺ°зҪ‘з»ңй”ҷиҜҜпјҢиҜ·йҮҚиҜ•гҖӮ', 'notice', 'normal', 'е»әи®®з”ЁжҲ·жЈҖжҹҘзҪ‘з»ңиҝһжҺҘеҗҺйҮҚиҜ•пјҢиӢҘй—®йўҳжҢҒз»ӯпјҢеҸҜиҒ”зі»жҠҖжңҜж”ҜжҢҒжҲ–жҹҘзңӢжңҚеҠЎзҠ¶жҖҒе…¬е‘ҠгҖӮ', '0', NULL);

-- ----------------------------
-- Table structure for community_activity
-- ----------------------------
DROP TABLE IF EXISTS `community_activity`;
CREATE TABLE `community_activity`  (
  `activity_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'жҙ»еҠЁIDпјҲдё»й”®пјү',
  `activity_title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'жҙ»еҠЁж Үйўҳ',
  `activity_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'жҙ»еҠЁеҲҶзұ»пјҲvolunteer:еҝ—ж„ҝжңҚеҠЎ, good_deed:еҘҪдәәеҘҪдәӢ, daily_share:ж—ҘеёёеҲҶдә«пјү',
  `activity_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'жҙ»еҠЁеҶ…е®№',
  `activity_time` datetime NOT NULL COMMENT 'жҙ»еҠЁж—¶й—ҙ',
  `activity_location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'жҙ»еҠЁең°зӮ№',
  `publisher_id` bigint NOT NULL COMMENT 'еҸ‘еёғдәәIDпјҲе…іиҒ”community_userиЎЁidпјү',
  `publisher_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'еҸ‘еёғдәәе§“еҗҚпјҲеҶ—дҪҷпјү',
  `signup_start_time` datetime NOT NULL COMMENT 'жҠҘеҗҚејҖе§Ӣж—¶й—ҙ',
  `signup_end_time` datetime NOT NULL COMMENT 'жҠҘеҗҚз»“жқҹж—¶й—ҙ',
  `max_participants` int NULL DEFAULT 0 COMMENT 'жңҖеӨ§еҸӮдёҺдәәж•°пјҲ0иЎЁзӨәж— йҷҗеҲ¶пјү',
  `current_participants` int NULL DEFAULT 0 COMMENT 'еҪ“еүҚжҠҘеҗҚдәәж•°',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'жҙ»еҠЁзҠ¶жҖҒпјҲdraft:иҚүзЁҝ, published:е·ІеҸ‘еёғ, ongoing:иҝӣиЎҢдёӯ, completed:е·Із»“жқҹ, cancelled:е·ІеҸ–ж¶Ҳпјү',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'еҲӣе»әж—¶й—ҙ',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'жӣҙж–°ж—¶й—ҙ',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT 'еӨҮжіЁ',
  PRIMARY KEY (`activity_id`) USING BTREE,
  INDEX `idx_activity_type`(`activity_type` ASC) USING BTREE COMMENT 'жҙ»еҠЁеҲҶзұ»зҙўеј•',
  INDEX `idx_publisher_id`(`publisher_id` ASC) USING BTREE COMMENT 'еҸ‘еёғдәәIDзҙўеј•',
  INDEX `idx_activity_status`(`status` ASC) USING BTREE COMMENT 'жҙ»еҠЁзҠ¶жҖҒзҙўеј•'
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'зӨҫеҢәжҙ»еҠЁиЎЁ' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of community_activity
-- ----------------------------
