  `unit` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'еҚ•е…ғ',
  `room` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'жҲҝй—ҙеҸ·',
  `usage_amount` decimal(10, 2) NULL DEFAULT NULL COMMENT 'з”ЁйҮҸпјҲж°ҙз”өж°”зӯүпјү',
