  `last_reading` decimal(10, 2) NULL DEFAULT NULL COMMENT 'дёҠжңҹиҜ»ж•°',
  `current_reading` decimal(10, 2) NULL DEFAULT NULL COMMENT 'жң¬жңҹиҜ»ж•°',
