  `user_room` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'дёҡдё»жҲҝеҸ·пјҲеҶ—дҪҷпјү',
  `read_month` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'и®Ўиҙ№жңҲд»ҪпјҲж јејҸпјҡYYYY-MMпјү',
