  `current_reading` decimal(10, 2) NOT NULL COMMENT 'жң¬ж¬ЎжҠ„иЎЁж•°пјҲеәҰпјү',
  `used_amount` decimal(10, 2) NOT NULL COMMENT 'е®һйҷ…з”Ёз”өйҮҸпјҲеәҰпјү',
  `unit_price` decimal(10, 2) NOT NULL COMMENT 'з”өиҙ№еҚ•д»·пјҲе…ғ/еәҰпјү',
  `total_fee` decimal(10, 2) NOT NULL COMMENT 'з”өиҙ№жҖ»йўқпјҲе…ғпјү',
  `fee_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'зјҙиҙ№зҠ¶жҖҒпјҲunpaid:жңӘзјҙиҙ№, paid:е·Ізјҙиҙ№, overdue:йҖҫжңҹпјү',
  `due_date` datetime NOT NULL COMMENT 'зјҙиҙ№жҲӘжӯўж—Ҙжңҹ',
  `payment_time` datetime NULL DEFAULT NULL COMMENT 'зјҙиҙ№ж—¶й—ҙ',
  `payment_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT 'зјҙиҙ№и®ўеҚ•еҸ·',
  `overdue_amount` decimal(10, 2) NULL DEFAULT 0.00 COMMENT 'йҖҫжңҹж»һзәійҮ‘пјҲе…ғпјү',
