  `surplus_electricity` double NULL DEFAULT NULL COMMENT 'еү©дҪҷз”өйҮҸпјҲеәҰпјү',
  PRIMARY KEY (`electricity_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE COMMENT 'дёҡдё»IDзҙўеј•',
  INDEX `idx_read_month`(`read_month` ASC) USING BTREE COMMENT 'и®Ўиҙ№жңҲд»Ҫзҙўеј•',
  INDEX `idx_fee_status`(`fee_status` ASC) USING BTREE COMMENT 'зјҙиҙ№зҠ¶жҖҒзҙўеј•'
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'з”өиҙ№иЎЁ' ROW_FORMAT = DYNAMIC;

