DROP TABLE IF EXISTS `community_notice`;
CREATE TABLE `community_notice`  (
  `notice_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'йҖҡзҹҘID',
  `notice_title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'йҖҡзҹҘж Үйўҳ',
  `notice_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'йҖҡзҹҘеҶ…е®№',
  `notice_type` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '1' COMMENT 'йҖҡзҹҘзұ»еһӢпјҲ1:е…¬е‘Ҡ,2:йҖҡзҹҘ,3:зҙ§жҖҘпјү',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT 'зҠ¶жҖҒпјҲ0:жӯЈеёё,1:е…ій—ӯпјү',
  `is_top` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT 'жҳҜеҗҰзҪ®йЎ¶пјҲ0:еҗҰ,1:жҳҜпјү',
  `publish_time` datetime NULL DEFAULT NULL COMMENT 'еҸ‘еёғж—¶й—ҙ',
  `publisher` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'еҸ‘еёғдәә',
  `community_id` bigint NULL DEFAULT NULL COMMENT 'е°ҸеҢәID',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT 'еҲӣе»әиҖ…',
  `create_time` datetime NULL DEFAULT NULL COMMENT 'еҲӣе»әж—¶й—ҙ',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT 'жӣҙж–°иҖ…',
  `update_time` datetime NULL DEFAULT NULL COMMENT 'жӣҙж–°ж—¶й—ҙ',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'еӨҮжіЁ',
  `read_count` int NULL DEFAULT 0 COMMENT 'йҳ…иҜ»ж¬Ўж•°',
  PRIMARY KEY (`notice_id`) USING BTREE,
  INDEX `idx_notice_type`(`notice_type` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_is_top`(`is_top` ASC) USING BTREE,
  INDEX `idx_publish_time`(`publish_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'зӨҫеҢәйҖҡзҹҘиЎЁ' ROW_FORMAT = DYNAMIC;

