INSERT INTO `community_post` VALUES (1, 1, 'зҺӢеӨ§зҲ·', 'д»ҠеӨ©еңЁе°ҸеҢәиҪҰеә“еҮәеҸЈжҚЎеҲ°дәҶдёҖдёӘй’ұеҢ…пјҢе·Із»ҸдәӨз»ҷдҝқе®үдәӯе№¶зү©еҪ’еҺҹдё»е•ҰгҖӮеӨ§е®¶еҮәиЎҢиҰҒжіЁж„Ҹе®үе…ЁпјҢзңӢз®ЎеҘҪйҡҸиә«зү©е“ҒгҖӮ', '#еҘҪдәәеҘҪдәӢ', 12, 4, 5, '0', '2026-03-26 19:38:41', '2026-03-26 19:38:41');
INSERT INTO `community_post` VALUES (2, 2, 'жқҺе°ҸзҫҺ', 'жҘјдёӢзҡ„жЁұиҠұејҖеҫ—жӯЈеҘҪпјҢдёӢеҚҲйҳіе…үжҙ’иҝӣжқҘзҡ„ж—¶еҖҷзңҹзҡ„еҘҪзҫҺпјҒжҺЁиҚҗеӨ§е®¶еҺ»еҚ—й—Ёйҷ„иҝ‘жү“еҚЎгҖӮ', '#ж—ҘеёёеҲҶдә«', 18, 1, 2, '0', '2026-03-26 19:38:41', '2026-03-26 19:38:41');
INSERT INTO `community_post` VALUES (3, 3, 'еј е…Ҳз”ҹ', 'еҲҡеҲҡдёәзӨҫеҢәеҫ®еһӢеӣҫд№ҰйҰҶжҚҗиө дәҶ20жң¬зІҫиЈ…з«ҘиҜқд№ҰпјҢеёҢжңӣз»ҷеӯ©еӯҗд»¬еёҰеҺ»дёҚдёҖж ·зҡ„з«Ҙе№ҙгҖӮ', '#зҲұеҝғжҚҗж¬ҫ', 24, 0, 10, '0', '2026-03-26 19:38:41', '2026-03-26 19:38:41');
