  `reservation_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'йў„зәҰзұ»еһӢпјҲpark:иҪҰдҪҚйў„зәҰ, repair:з»ҙдҝ®йў„зәҰ, gym:еҒҘиә«жҲҝйў„зәҰпјү',
