-- ----------------------------
-- Table structure for community_task
-- ----------------------------
DROP TABLE IF EXISTS `community_task`;
CREATE TABLE `community_task`  (
  `task_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'д»»еҠЎID',
  `task_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'д»»еҠЎеҗҚз§°',
  `task_desc` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'д»»еҠЎжҸҸиҝ°',
  `task_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'д»»еҠЎзұ»еһӢ: daily-ж—Ҙеёёд»»еҠЎ, special-дё“еұһд»»еҠЎ',
  `task_icon` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'д»»еҠЎеӣҫж Ү',
  `points_reward` int NOT NULL DEFAULT 0 COMMENT 'з§ҜеҲҶеҘ–еҠұ',
  `task_action` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'д»»еҠЎеҠЁдҪңж ҮиҜҶ: signin, post, comment, like, complete_profile, invite, survey, activity',
  `max_times` int NULL DEFAULT 1 COMMENT 'жҜҸж—ҘжңҖеӨ§е®ҢжҲҗж¬Ўж•°',
  `sort_order` int NULL DEFAULT 0 COMMENT 'жҺ’еәҸ',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT 'зҠ¶жҖҒ: 0-еҗҜз”Ё, 1-зҰҒз”Ё',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'еҲӣе»әж—¶й—ҙ',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'жӣҙж–°ж—¶й—ҙ',
  PRIMARY KEY (`task_id`) USING BTREE,
  INDEX `idx_type`(`task_type` ASC) USING BTREE,
  INDEX `idx_action`(`task_action` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 17 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'з§ҜеҲҶд»»еҠЎе®ҡд№үиЎЁ' ROW_FORMAT = DYNAMIC;

