  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'дё»й”®IDпјҲдҪҸжҲ·е”ҜдёҖж ҮиҜҶпјү',
  `name` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'дҪҸжҲ·е§“еҗҚ',
  `phone` varchar(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'жүӢжңәеҸ·пјҲ11дҪҚпјҢе”ҜдёҖпјү',
  `id_card` varchar(18) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'иә«д»ҪиҜҒеҸ·пјҲеҸҜйҖүпјҢи„ұж•ҸеӯҳеӮЁпјү',
  `gender` tinyint NULL DEFAULT NULL COMMENT 'жҖ§еҲ«пјҡ0-жңӘзҹҘпјҢ1-з”·пјҢ2-еҘі',
  `birthday` date NULL DEFAULT NULL COMMENT 'еҮәз”ҹж—Ҙжңҹ',
  `live_data` date NULL DEFAULT NULL COMMENT 'е…ҘдҪҸж—Ҙжңҹ',
  `specific_address` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'е…·дҪ“дҪҸеқҖпјҲеҰӮпјҡ3еҸ·жҘј2еҚ•е…ғ08е®Ө/10еҸ·жҘј1еҚ•е…ғ102е®Өпјү',
  `emergency_contact` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'зҙ§жҖҘиҒ”зі»дәәе§“еҗҚ',
  `emergency_phone` varchar(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'зҙ§жҖҘиҒ”зі»дәәжүӢжңәеҸ·',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'еҲӣе»әж—¶й—ҙ',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'жӣҙж–°ж—¶й—ҙ',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'еҲӣе»әдәә',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'жӣҙж–°дәә',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'еӨҮжіЁпјҲеҰӮпјҡзү№ж®ҠйңҖжұӮгҖҒеӨҮжіЁдҝЎжҒҜпјү',
  `password` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT 'еҜҶз Ғ',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `phone`(`phone` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 121 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'дҪҸжҲ·дҝЎжҒҜиЎЁ' ROW_FORMAT = DYNAMIC;

