  `water_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ж°ҙиҙ№IDпјҲдё»й”®пјү',
  `user_id` bigint NOT NULL COMMENT 'дёҡдё»IDпјҲе…іиҒ”community_userиЎЁidпјү',
  `user_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'дёҡдё»е§“еҗҚпјҲеҶ—дҪҷпјү',
